mapper.select:
select log_id, supplier_id, hospital_id, certificate_id, change_type, before_json, after_json, create_by, create_time
from scm_supplier_cert_change_log


        and supplier_id = #{supplierId}


        and hospital_id = #{hospitalId}


        and certificate_id = #{certificateId}


        and change_type = #{changeType}


order by create_time desc
